using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    // Splits text on sentence-ending punctuation followed by whitespace or end-of-string.
    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();

        if (sentences.Count <= maxSentences)
        {
            return string.Join(" ", sentences);
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Sentence: sentence, Score: ScoreSentence(sentence, wordFrequencies), Index: index))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static Dictionary<string, double> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        // Normalize by max frequency
        if (freq.Count > 0)
        {
            var max = freq.Values.Max();
            foreach (var key in freq.Keys)
            {
                freq[key] /= max;
            }
        }

        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, double> wordFrequencies)
    {
        var words = GetWords(sentence);
        if (words.Length == 0) return 0;

        return words.Sum(w => wordFrequencies.GetValueOrDefault(w));
    }

    private static string[] GetWords(string text) =>
        text.Split([' ', '\t', '\r', '\n'], StringSplitOptions.RemoveEmptyEntries)
            .Select(w => w.Trim('.', ',', '!', '?', ';', ':', '"', '\'', '(', ')'))
            .Where(w => w.Length > 0)
            .ToArray();

    public static int CountWords(string text) =>
        text.Split([' ', '\t', '\r', '\n'], StringSplitOptions.RemoveEmptyEntries).Length;
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _service.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = DocumentSummarizationService.CountWords(request.DocumentText),
            SummaryWordCount = DocumentSummarizationService.CountWords(summary)
        });
    }
}

